class Solution:
    def maxFreeTime(self, eventTime, startTime, endTime):
        n = len(startTime)
        gaps = [startTime[0]]
        for i in range(1, n):
            gaps.append(startTime[i] - endTime[i - 1])
        gaps.append(eventTime - endTime[-1])
        durations = [endTime[i] - startTime[i] for i in range(n)]
        ranked = sorted(range(len(gaps)), key=lambda j: -gaps[j])[:3]
        best = max(gaps)
        for i in range(n):
            merged = gaps[i] + gaps[i + 1]
            other_max = 0
            for j in ranked:
                if j != i and j != i + 1:
                    other_max = gaps[j]
                    break
            candidate = merged + (durations[i] if other_max >= durations[i] else 0)
            if candidate > best:
                best = candidate
        return best

