var maxFreeTime = function(eventTime, startTime, endTime) {
    const n = startTime.length;
    const gaps = [startTime[0]];
    for (let i = 1; i < n; i++) gaps.push(startTime[i] - endTime[i - 1]);
    gaps.push(eventTime - endTime[n - 1]);
    const durations = [];
    for (let i = 0; i < n; i++) durations.push(endTime[i] - startTime[i]);
    const order = gaps.map((_, j) => j).sort((a, b) => gaps[b] - gaps[a]).slice(0, 3);
    let best = Math.max(...gaps);
    for (let i = 0; i < n; i++) {
        const merged = gaps[i] + gaps[i + 1];
        let otherMax = 0;
        for (const j of order) {
            if (j !== i && j !== i + 1) { otherMax = gaps[j]; break; }
        }
        const candidate = merged + (otherMax >= durations[i] ? durations[i] : 0);
        if (candidate > best) best = candidate;
    }
    return best;
};
